#include<bits/stdc++.h>
using namespace std;
int qian[3][3] = {
	{1, 2, 3},
	{0, 1, 2},
	{0, 0, 1}
};
int fang[5] = {0, 0, 0, -1, 1};
int  v[101][101];
int n, m, qix, qiy, zhongx, zhongy, kaifang;
char c;
int bfs() {
	queue<int> q[4];
	q[0].push(qix);
	q[1].push(qiy);
	//ksksksk
	q[2].push(0);
	q[3].push(kaifang);
	v[qix][qiy] = 1;
	while (!q[0].empty()) {
		int x = q[0].front();
		int y = q[1].front();
		int srtp = q[2].front();
		int fangg = q[3].front();
		q[0].pop();
		q[1].pop();
		q[2].pop();
		q[3].pop();
		if (x == zhongx && y == zhongy) return srtp;
		for (int i = 0; i < 5; i++) {
			if (i < 3) {
				if (fangg == 1) {
					for (int j = 0; j < 3; j++) if (y - qian[i][j] <= 1 || v[x][y + qian[i][j]] == 2) continue;

					if (v[x][y - qian[i][0]] == 1) {
						q[0].push(x);
						q[1].push(y - qian[i][0]);
						q[2].push(srtp + 1);
						q[3].push(fangg);
						v[x][y - qian[i][0]] = 1;
					}

				}
				if (fangg == 2) {
					for (int j = 0; j < 3; j++) if (x - qian[i][j] <= 1 || v[x][y + qian[i][j]] == 2) continue;
					if (v[x - qian[i][0]][y] == 1) {
						q[0].push(x - qian[i][0]);
						q[1].push(y);
						q[2].push(srtp + 1);
						q[3].push(fangg);
						v[x - qian[i][0]][y] = 1;
					}

				}
				if (fangg == 3) {
					for (int j = 0; j < 3; j++) if (y + qian[i][j] >= m || v[x][y + qian[i][j]] == 2) continue;
					if (!v[x][y + qian[i][0]]) {
						q[0].push(x);
						q[1].push(y + qian[i][0]);
						q[2].push(srtp + 1);
						q[3].push(fangg);
						v[x][y + qian[i][0]] = 1;
					}

				}

				if (fangg == 4) {
					for (int j = 0; j < 3; j++) if (x + qian[i][j] >= n || v[x][y + qian[i][j]] == 2) continue;
					if (!v[x + qian[i][0]][y]) {
						q[0].push(x + qian[i][0]);
						q[1].push(y);
						q[2].push(srtp + 1);
						q[3].push(fangg);
						v[x + qian[i][0]][y] = 1;
					}
				}
			} else {
				int fagg = fangg + fang[i];
				if (fagg <= 0) fagg = 4;
				else if (fagg > 4) fagg = 1;
				q[0].push(x);
				q[1].push(y);
				q[2].push(srtp + 1);
				q[3].push(fagg);
			}
		}
	}
	return -1;
}
int main() {
	cin >> n >> m;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= m; j++) {

			cin >> v[i][j];;

			if (v[i][j] == 1) {
				v[i][j] = 1;
				v[i + 1][j] = 2;
				v[i + 1][j + 1] = 2;
				v[i][j + 1] = 2;
			}
		}
	}

	cin >> qix >> qiy >> zhongx >> zhongy;
	cin >> c;
	if (c == 'E') kaifang = 1;
	if (c == 'S') kaifang = 2;
	if (c == 'W') kaifang = 3;
	if (c == 'N') kaifang = 4;

	cout << bfs();
	return 0;
}
